import React, { useState } from 'react';

export default function AddPost(props) {
    const [title, setTitle] = useState("")
    const [info, setInfo] = useState("")
    const [errMsg, setErrMsg] = useState("")

    const checkTitle = (event) => {
        let input = event.traget.value
        if (input.length >= 2) {
            setTitle(input)
            setErrMsg("")
        }
        else {
            setTitle('')
            setErrMsg("Title is too short")
        }
    }
    const checkInfo = (event) => {
        let input = event.traget.value
        if (input.length >= 2) {
            setInfo(input)
            setErrMsg("")
        }
        else {
            setInfo('')
            setErrMsg("Info is too short")
        }
        const addPost = ()=>{
            if(errMsg&&title.length>2&&info.length>2){
            props.newPost(title, info)
            setErrMsg("")
        }
        else{
            setErrMsg("please fill up all the information")
        }



        }
    }
    return (
        <div>
            <h4>Add new Post</h4>
            Title : <input id={"title"} onChange={checkTitle} type={"text"} /><br />
            Info : <input id={"info"} onChange={checkInfo} type={"text"} /><br />
            <button type='Submit' onClick={() => {addPost }}>Send</button>
            <p>{errMsg}</p>




        </div>

    )
}
